import{_ as t,c as e,o as r,a2 as o}from"./chunks/framework.Sicmpk4x.js";const v=JSON.parse('{"title":"","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"book/overview.md","filePath":"book/overview.md"}'),a={name:"book/overview.md"},d=o('<p>This little book contains a series of course projects based on <a href="https://github.com/yhzhang0128/egos-2000" target="_blank"> egos-2000</a>. The goal is to help students gain experience and confidence in creating their own operating system or similar computer systems in their future career.</p><div class="warning custom-block"><p class="custom-block-title">“What I cannot create, I do not understand.”</p><p>— Richard Feynman, Nobel Prize in Physics in 1965</p></div><h2 id="core-projects" tabindex="-1">Core projects <a class="header-anchor" href="#core-projects" aria-label="Permalink to &quot;Core projects&quot;">​</a></h2><p>There are 6 <strong>core projects</strong> covering most of the OS concepts for an undergraduate-level OS course (e.g., CS4411 at Cornell). These core projects <em>introduce the architectural support for OS one-by-one</em>, which students at Cornell found very helpful. For example, students could implement a preemptive scheduler without any knowledge of privilege levels.</p><table tabindex="0"><thead><tr><th></th><th>OS concepts</th><th>Architectural support</th></tr></thead><tbody><tr><td>Hello, World!</td><td>memory, pointer</td><td>user-level ISA</td></tr><tr><td>Multithreading 101</td><td>thread, context switch</td><td></td></tr><tr><td>Preemptive Scheduler</td><td>interrupt handling, scheduling priority</td><td>timer interrupt, CLINT</td></tr><tr><td>System Call</td><td>exception handling, inter-process communication</td><td>control and status register, privilege level</td></tr><tr><td>Page Table Translation</td><td>process address space</td><td>virtual memory</td></tr><tr><td>File System</td><td>inode, file, directory</td><td></td></tr></tbody></table><h2 id="advanced-projects" tabindex="-1">Advanced projects <a class="header-anchor" href="#advanced-projects" aria-label="Permalink to &quot;Advanced projects&quot;">​</a></h2><p>There are 3 <strong>advanced projects</strong> for a master-level OS course (e.g., CS5411 at Cornell). All the projects can run on the QEMU emulator as well as actual RISC-V boards.</p><table tabindex="0"><thead><tr><th></th><th>OS concepts</th><th>Architectural support</th></tr></thead><tbody><tr><td>SD Card Driver</td><td>I/O bus controller</td><td>memory-mapped I/O</td></tr><tr><td>Ethernet and UDP</td><td>four layers of TCP/IP</td><td>device interrupt, PLIC</td></tr><tr><td>Multi-core and Lock</td><td>spinlock, bootstrap, critical section</td><td>atomic memory operation (AMO)</td></tr></tbody></table><p>Now, let&#39;s get hands dirty and have fun!</p>',9),n=[d];function s(c,i,l,p,h,u){return r(),e("div",null,n)}const b=t(a,[["render",s]]);export{v as __pageData,b as default};
